'use client';

import * as React from 'react';

import { type ItemInstance } from '@headless-tree/core';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuLabel,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from '@/components/jetbrains-ui/context-menu';
import { ScrollArea, ScrollViewport } from '@/components/jetbrains-ui/scroll-area';
import { ChevronDown } from '@/components/jetbrains-ui/icons/general/general/chevron-down';
import { Delete } from '@/components/jetbrains-ui/icons/general/general/delete';
import { ChevronRight } from '@/components/jetbrains-ui/icons/general/general/chevron-right';
import { Loader } from '@/components/jetbrains-ui/icons/general/spinner/loader';
import './index.css';

export { asyncDataLoaderFeature } from './feature';

export interface DynamicTreeItemData {
  label?: string;
  icon?: React.ReactNode;
  endContent?: React.ReactNode;
  disabled?: boolean;
  isFolder?: boolean;
}

export interface DynamicTreeItemProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  item: ItemInstance<TItem>;
  indent: number;
}

export interface DynamicTreeItemComponent<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  (props: DynamicTreeItemProps<TItem>): React.ReactNode;
}

export interface DynamicTreeContextMenuProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  item: ItemInstance<TItem>;
}

export interface DynamicTreeContextMenuComponent<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> {
  (props: DynamicTreeContextMenuProps<TItem>): React.ReactNode;
}

export interface DynamicTreeProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> extends Omit<
    React.ComponentPropsWithoutRef<'div'>,
    'children' | 'className' | 'style' | 'contextMenu'
  > {
  containerProps: React.ComponentPropsWithoutRef<'div'>;
  items: ItemInstance<TItem>[];
  indent?: number;
  item?: DynamicTreeItemComponent<TItem>;
  contextMenu?: DynamicTreeContextMenuComponent<TItem> | null;
  width?: React.CSSProperties['width'];
  height?: React.CSSProperties['height'];
}

type DynamicTreeItemButtonStyle = React.CSSProperties & {
  '--jb-tree-item-padding-left': string;
};

type DynamicTreeAsyncItemInstance<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> = ItemInstance<TItem> & {
  invalidateItemData?: (optimistic?: boolean) => Promise<void>;
  invalidateChildrenIds?: (optimistic?: boolean) => Promise<void>;
};

type DynamicTreeMutableParentItem<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> = ItemInstance<TItem> & {
  updateCachedChildrenIds?: (
    childrenIds: string[],
    skipUpdateTree?: boolean,
  ) => void;
};

type DynamicTreeMutableItem<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> = ItemInstance<TItem> & {
  clearCachedChildren?: (skipUpdateTree?: boolean) => void;
};

function canRefreshDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const asyncItem = item as DynamicTreeAsyncItemInstance<TItem>;

  return (
    typeof asyncItem.invalidateItemData === 'function' ||
    (item.isFolder() && typeof asyncItem.invalidateChildrenIds === 'function')
  );
}

function canDeleteDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const parent = item.getParent() as
    | DynamicTreeMutableParentItem<TItem>
    | undefined;

  return typeof parent?.updateCachedChildrenIds === 'function';
}

function canClearDynamicTreeItemChildren<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const mutableItem = item as DynamicTreeMutableItem<TItem>;

  return (
    item.isFolder() && typeof mutableItem.clearCachedChildren === 'function'
  );
}

async function refreshDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const asyncItem = item as DynamicTreeAsyncItemInstance<TItem>;

  if (typeof asyncItem.invalidateItemData === 'function') {
    await asyncItem.invalidateItemData();
  }

  if (
    item.isFolder() &&
    typeof asyncItem.invalidateChildrenIds === 'function'
  ) {
    await asyncItem.invalidateChildrenIds();
  }
}

function deleteDynamicTreeItem<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const parent = item.getParent() as
    | DynamicTreeMutableParentItem<TItem>
    | undefined;

  if (typeof parent?.updateCachedChildrenIds !== 'function') {
    return;
  }

  parent.updateCachedChildrenIds(
    parent
      .getChildren()
      .filter((child) => child.getId() !== item.getId())
      .map((child) => child.getId()),
  );
  parent.setFocused();
}

function clearDynamicTreeItemChildren<TItem extends DynamicTreeItemData>(
  item: ItemInstance<TItem>,
) {
  const mutableItem = item as DynamicTreeMutableItem<TItem>;

  if (
    !item.isFolder() ||
    typeof mutableItem.clearCachedChildren !== 'function'
  ) {
    return;
  }

  item.setFocused();

  if (item.isExpanded()) {
    item.collapse();
  }

  mutableItem.clearCachedChildren();
}

export interface DynamicTreeItemContextMenuProps<
  TItem extends DynamicTreeItemData = DynamicTreeItemData,
> extends DynamicTreeContextMenuProps<TItem> {}

function DynamicTreeItemContextMenu<TItem extends DynamicTreeItemData>({
  item,
}: DynamicTreeItemContextMenuProps<TItem>) {
  return (
    <>
      <ContextMenuLabel>
        {item.getItemData()?.label ?? item.getId()}
      </ContextMenuLabel>
      <ContextMenuItem
        inset
        disabled={!canRefreshDynamicTreeItem(item)}
        onSelect={() => {
          void refreshDynamicTreeItem(item);
        }}
      >
        Refresh
      </ContextMenuItem>
      <ContextMenuItem
        inset
        disabled={!canClearDynamicTreeItemChildren(item)}
        onSelect={() => {
          clearDynamicTreeItemChildren(item);
        }}
      >
        Clear Children
      </ContextMenuItem>
      <ContextMenuSeparator />
      <ContextMenuItem
        inset
        variant="destructive"
        disabled={!canDeleteDynamicTreeItem(item)}
        onSelect={() => {
          deleteDynamicTreeItem(item);
        }}
      >
        <Delete className="shrink-0" size="md" />
        <span>Delete</span>
      </ContextMenuItem>
    </>
  );
}

function DynamicTreeItem<TItem extends DynamicTreeItemData>({
  indent,
  item,
}: DynamicTreeItemProps<TItem>) {
  const {
    style: resolvedStyle,
    tabIndex: resolvedTabIndex,
    ...resolvedProps
  } = item.getProps() as React.ComponentPropsWithoutRef<'div'>;

  return (
    <div
      data-slot="jb-tree-item"
      data-value={item.getId()}
      className="jb-tree-item my-0.5 p-0"
    >
      <div
        {...resolvedProps}
        data-slot="jb-tree-item-button"
        data-value={item.getId()}
        data-has-children={item.isFolder() ? 'true' : undefined}
        data-selected={item.isSelected() ? 'true' : undefined}
        data-disabled={
          (item.getItemData() as TItem | null)?.disabled ? 'true' : undefined
        }
        data-expanded={
          item.isFolder() && item.isExpanded() ? 'true' : undefined
        }
        data-loading={item.isLoading() ? 'true' : undefined}
        aria-selected={item.isSelected()}
        aria-disabled={
          (item.getItemData() as TItem | null)?.disabled ? true : undefined
        }
        aria-busy={item.isLoading() ? true : undefined}
        tabIndex={
          (item.getItemData() as TItem | null)?.disabled
            ? -1
            : (resolvedTabIndex ?? -1)
        }
        style={
          {
            ...resolvedStyle,
            '--jb-tree-item-padding-left': `${
              16 +
              item.getItemMeta().level * indent +
              Math.max(0, item.getItemMeta().level - 1) * 2
            }px`,
          } as DynamicTreeItemButtonStyle
        }
        className="jb-tree-item-button relative box-border flex h-6 w-full min-w-0 cursor-default items-center gap-0.5 pr-4 pl-[var(--jb-tree-item-padding-left)] select-none outline-none transition-[color] duration-150 ease-in-out data-[disabled=true]:cursor-not-allowed"
      >
        <span
          aria-hidden="true"
          data-slot="jb-tree-item-overlay"
          className="jb-tree-item-overlay pointer-events-none absolute inset-y-0 left-3 right-3 rounded-[4px] transition-[background-color,box-shadow] duration-150 ease-in-out"
        />

        {item.isFolder() ? (
          <button
            data-slot="jb-tree-item-disclosure"
            data-value={item.getId()}
            data-expanded={item.isExpanded() ? 'true' : undefined}
            data-loading={item.isLoading() ? 'true' : undefined}
            type="button"
            className="jb-tree-item-disclosure relative z-10 inline-flex size-4 shrink-0 items-center justify-center border-0 bg-transparent p-0 outline-none disabled:cursor-not-allowed"
            aria-label={
              item.isLoading()
                ? `Loading ${(item.getItemData() as TItem | null)?.label ?? item.getId()}`
                : item.isExpanded()
                  ? `Collapse ${(item.getItemData() as TItem | null)?.label ?? item.getId()}`
                  : `Expand ${(item.getItemData() as TItem | null)?.label ?? item.getId()}`
            }
            onClick={(event) => {
              event.stopPropagation();

              if ((item.getItemData() as TItem | null)?.disabled) {
                return;
              }

              item.setFocused();

              if (item.isExpanded()) {
                item.collapse();
              } else {
                item.expand();
              }
            }}
            disabled={Boolean((item.getItemData() as TItem | null)?.disabled)}
          >
            {item.isLoading() ? (
              <Loader
                className="animate-spin [animation-duration:900ms]"
                size="md"
              />
            ) : item.isExpanded() ? (
              <ChevronDown className="scale-[0.78]" size="md" />
            ) : (
              <ChevronRight className="scale-[0.78]" size="md" />
            )}
          </button>
        ) : (
          <span
            data-slot="jb-tree-item-disclosure-placeholder"
            aria-hidden="true"
            className="jb-tree-item-disclosure-placeholder relative z-10 inline-flex size-4 shrink-0 items-center justify-center"
          />
        )}
        <span
          data-slot="jb-tree-item-content"
          className="jb-tree-item-content relative z-10 inline-flex h-5 min-w-0 flex-1 items-center gap-1.5"
        >
          {(item.getItemData() as TItem | null)?.icon ? (
            <span
              data-slot="jb-tree-item-icon"
              className="jb-tree-item-icon inline-flex size-4 shrink-0 items-center justify-center [&>svg]:size-4"
            >
              {(item.getItemData() as TItem | null)?.icon}
            </span>
          ) : null}

          <span
            data-slot="jb-tree-item-label"
            className="jb-tree-item-label min-w-0 overflow-hidden text-ellipsis whitespace-nowrap"
          >
            {(item.getItemData() as TItem | null)?.label ?? item.getId()}
          </span>

          {(item.getItemData() as TItem | null)?.endContent ? (
            <span
              data-slot="jb-tree-item-end"
              className="jb-tree-item-end ml-auto pr-0.5 text-[13px] leading-4 font-medium"
            >
              {(item.getItemData() as TItem | null)?.endContent}
            </span>
          ) : null}
        </span>
      </div>
    </div>
  );
}

function DynamicTree<TItem extends DynamicTreeItemData>({
  containerProps,
  items,
  indent = 16,
  item: customItem,
  contextMenu,
  width,
  height,
  ...props
}: DynamicTreeProps<TItem>) {
  const ItemComponent = customItem ?? DynamicTreeItem;
  const ContextMenuComponent =
    contextMenu === undefined
      ? (DynamicTreeItemContextMenu as DynamicTreeContextMenuComponent<TItem>)
      : contextMenu;

  return (
    <ScrollArea
      data-slot="jb-tree-scroll-area"
      className="max-w-full p-2"
      style={{ width, height }}
    >
      <ScrollViewport data-slot="jb-tree-scroll-viewport" className="size-full">
        <div
          {...containerProps}
          data-slot="jb-tree"
          className="jb-tree jb-dynamic-tree block w-full min-w-[244px] box-border py-2 text-[13px] leading-4 font-medium [font-family:var(--jb-font-sans),sans-serif]"
          {...props}
        >
          {items.map((item) => {
            if (!ContextMenuComponent) {
              return (
                <ItemComponent
                  key={item.getKey()}
                  item={item}
                  indent={indent}
                />
              );
            }

            return (
              <ContextMenu key={item.getKey()}>
                <ContextMenuTrigger
                  asChild
                  onContextMenu={(event) => {
                    if ((item.getItemData() as TItem | null)?.disabled) {
                      event.preventDefault();
                      return;
                    }

                    item.setFocused();
                    item.select();
                  }}
                >
                  <div
                    data-slot="jb-tree-item-context-trigger"
                    data-value={item.getId()}
                  >
                    <ItemComponent item={item} indent={indent} />
                  </div>
                </ContextMenuTrigger>
                <ContextMenuContent>
                  {ContextMenuComponent({
                    item,
                  })}
                </ContextMenuContent>
              </ContextMenu>
            );
          })}
        </div>
      </ScrollViewport>
    </ScrollArea>
  );
}

export { DynamicTreeItemContextMenu };
export { DynamicTreeItem };
export { DynamicTree };

export default DynamicTree;

import {
  type AsyncDataLoaderDataRef,
  type FeatureImplementation,
  makeStateUpdater,
  type TreeInstance,
} from '@headless-tree/core';

const getItemId = (itemId: string) => itemId.split('@')[0] ?? itemId;

const getDataRef = <T>(tree: TreeInstance<T>) => {
  const dataRef = tree.getDataRef<AsyncDataLoaderDataRef<T>>();
  dataRef.current.itemData ??= {};
  dataRef.current.childrenIds ??= {};
  dataRef.current.loadingDataSubs ??= {};
  dataRef.current.loadingChildrenSubs ??= {};
  return dataRef;
};

const loadItemData = async <T>(tree: TreeInstance<T>, itemId: string) => {
  const config = tree.getConfig();
  const dataRef = getDataRef(tree);
  const realItemId = getItemId(itemId);

  if (tree.getState().loadingItemData.includes(realItemId)) {
    return new Promise<T>((resolve) => {
      dataRef.current.loadingDataSubs[realItemId] ??= [];
      dataRef.current.loadingDataSubs[realItemId].push(() => {
        resolve(dataRef.current.itemData[realItemId]);
      });
    });
  }

  if (!dataRef.current.itemData[realItemId]) {
    tree.applySubStateUpdate('loadingItemData', (loadingItemData) => [
      ...loadingItemData,
      realItemId,
    ]);
  }

  const item = await config.dataLoader.getItem(itemId);
  dataRef.current.itemData[realItemId] = item;
  config.onLoadedItem?.(realItemId, item);
  tree.applySubStateUpdate('loadingItemData', (loadingItemData) =>
    loadingItemData.filter((id) => id !== realItemId),
  );
  dataRef.current.loadingDataSubs[realItemId]?.forEach((callback) =>
    callback(),
  );

  return item;
};

const loadChildrenIds = async <T>(tree: TreeInstance<T>, itemId: string) => {
  const config = tree.getConfig();
  const dataRef = getDataRef(tree);
  let childrenIds: string[];

  if (tree.getState().loadingItemChildrens.includes(itemId)) {
    return new Promise<string[]>((resolve) => {
      dataRef.current.loadingChildrenSubs[itemId] ??= [];
      dataRef.current.loadingChildrenSubs[itemId].push(() => {
        resolve(dataRef.current.childrenIds[itemId]);
      });
    });
  }

  if (!dataRef.current.childrenIds[itemId]) {
    tree.applySubStateUpdate('loadingItemChildrens', (loadingItemChildrens) => [
      ...loadingItemChildrens,
      itemId,
    ]);
  }

  if ('getChildrenWithData' in config.dataLoader) {
    const children = await config.dataLoader.getChildrenWithData(itemId);
    childrenIds = children.map((child) => child.id);
    dataRef.current.childrenIds[itemId] = childrenIds;
    children.forEach(({ id, data }) => {
      dataRef.current.itemData[id] = data;
      config.onLoadedItem?.(id, data);
    });

    config.onLoadedChildren?.(itemId, childrenIds);
    tree.rebuildTree();
    tree.applySubStateUpdate('loadingItemData', (loadingItemData) =>
      loadingItemData.filter((id) => !childrenIds.includes(id)),
    );
  } else {
    childrenIds = await config.dataLoader.getChildren(itemId);
    dataRef.current.childrenIds[itemId] = childrenIds;
    config.onLoadedChildren?.(itemId, childrenIds);
    tree.rebuildTree();
  }

  tree.applySubStateUpdate('loadingItemChildrens', (loadingItemChildrens) =>
    loadingItemChildrens.filter((id) => id !== itemId),
  );
  dataRef.current.loadingChildrenSubs[itemId]?.forEach((callback) =>
    callback(),
  );

  return childrenIds;
};

const clearCachedChildrenCache = <T>(tree: TreeInstance<T>, itemId: string) => {
  const dataRef = getDataRef(tree);
  const childIds = dataRef.current.childrenIds[itemId] ?? [];

  delete dataRef.current.childrenIds[itemId];

  childIds.forEach((childId) => {
    clearCachedChildrenCache(tree, childId);
    delete dataRef.current.itemData[getItemId(childId)];
  });
};

const asyncDataLoaderItemInstance = {
  isLoading: ({ tree, item }) =>
    tree.getState().loadingItemData.includes(item.getItemMeta().itemId) ||
    tree.getState().loadingItemChildrens.includes(item.getItemMeta().itemId),
  invalidateItemData: async ({ tree, itemId }, optimistic) => {
    if (!optimistic) {
      delete getDataRef(tree).current.itemData?.[itemId];
    }

    await loadItemData(tree, `${itemId}@refresh`);
    tree.rebuildTree();
  },
  invalidateChildrenIds: async ({ tree, itemId }, optimistic) => {
    if (!optimistic) {
      delete getDataRef(tree).current.childrenIds?.[itemId];
    }

    await loadChildrenIds(tree, itemId);
  },
  updateCachedChildrenIds: ({ tree, itemId }, childrenIds, skipUpdateTree) => {
    getDataRef(tree).current.childrenIds[itemId] = childrenIds;

    if (!skipUpdateTree) {
      tree.rebuildTree();
    }
  },
  clearCachedChildren: (
    { tree, itemId }: { tree: TreeInstance<unknown>; itemId: string },
    skipUpdateTree?: boolean,
  ) => {
    clearCachedChildrenCache(tree, itemId);

    if (!skipUpdateTree) {
      tree.rebuildTree();
    }
  },
  updateCachedData: ({ tree, itemId }, data, skipUpdateTree) => {
    getDataRef(tree).current.itemData[itemId] = data;

    if (!skipUpdateTree) {
      tree.rebuildTree();
    }
  },
  hasLoadedData: ({ tree, itemId }) =>
    getDataRef(tree).current.itemData[itemId] !== undefined,
} as FeatureImplementation['itemInstance'] & {
  clearCachedChildren: (
    opts: { tree: TreeInstance<unknown>; itemId: string },
    skipUpdateTree?: boolean,
  ) => void;
};

export const asyncDataLoaderFeature: FeatureImplementation = {
  key: 'async-data-loader',

  getInitialState: (initialState) => ({
    loadingItemData: [],
    loadingItemChildrens: [],
    ...initialState,
  }),

  getDefaultConfig: (defaultConfig, tree) => ({
    setLoadingItemData: makeStateUpdater('loadingItemData', tree),
    setLoadingItemChildrens: makeStateUpdater('loadingItemChildrens', tree),
    ...defaultConfig,
  }),

  stateHandlerNames: {
    loadingItemData: 'setLoadingItemData',
    loadingItemChildrens: 'setLoadingItemChildrens',
  },

  treeInstance: {
    waitForItemDataLoaded: ({ tree }, itemId) => tree.loadItemData(itemId),

    waitForItemChildrenLoaded: ({ tree }, itemId) =>
      tree.loadChildrenIds(itemId),

    loadItemData: async ({ tree }, itemId) => {
      const realItemId = getItemId(itemId);

      return (
        getDataRef(tree).current.itemData[realItemId] ??
        (await loadItemData(tree, itemId))
      );
    },
    loadChildrenIds: async ({ tree }, itemId) => {
      return (
        getDataRef(tree).current.childrenIds[itemId] ??
        (await loadChildrenIds(tree, itemId))
      );
    },

    retrieveItemData: ({ tree }, itemId, skipFetch = false) => {
      const config = tree.getConfig();
      const dataRef = getDataRef(tree);
      const realItemId = getItemId(itemId);

      if (dataRef.current.itemData[realItemId]) {
        return dataRef.current.itemData[realItemId];
      }

      if (!tree.getState().loadingItemData.includes(realItemId) && !skipFetch) {
        setTimeout(() => loadItemData(tree, itemId));
      }

      return config.createLoadingItemData?.() ?? null;
    },

    retrieveChildrenIds: ({ tree }, itemId, skipFetch = false) => {
      const dataRef = getDataRef(tree);
      if (dataRef.current.childrenIds[itemId]) {
        return dataRef.current.childrenIds[itemId];
      }

      if (tree.getState().loadingItemChildrens.includes(itemId) || skipFetch) {
        return [];
      }

      setTimeout(() => loadChildrenIds(tree, itemId));

      return [];
    },
  },

  itemInstance:
    asyncDataLoaderItemInstance as FeatureImplementation['itemInstance'],
};

:root {
  --jb-tree-bg: transparent;
  --jb-tree-text: var(--jb-gray-1);
  --jb-tree-muted: var(--jb-gray-7);
  --jb-tree-icon: var(--jb-gray-6);
  --jb-tree-disclosure: var(--jb-gray-7);
  --jb-tree-disclosure-hover: var(--jb-gray-5);
  --jb-tree-item-hover-bg: var(--jb-gray-12);
  --jb-tree-item-active-bg: var(--jb-gray-11);
  --jb-tree-item-selected-bg: var(--jb-blue-11);
  --jb-tree-item-selected-text: var(--jb-gray-1);
  --jb-tree-focus-ring: var(--jb-blue-4);
  --jb-tree-focus-ring-offset: var(--jb-gray-14);
  --jb-tree-disabled-text: var(--jb-gray-8);
}

.dark {
  --jb-tree-bg: transparent;
  --jb-tree-text: var(--jb-gray-12);
  --jb-tree-muted: var(--jb-gray-7);
  --jb-tree-icon: var(--jb-gray-10);
  --jb-tree-disclosure: var(--jb-gray-10);
  --jb-tree-disclosure-hover: var(--jb-gray-12);
  --jb-tree-item-hover-bg: var(--jb-gray-3);
  --jb-tree-item-active-bg: var(--jb-gray-4);
  --jb-tree-item-selected-bg: var(--jb-blue-2);
  --jb-tree-item-selected-text: var(--jb-gray-12);
  --jb-tree-focus-ring: var(--jb-blue-6);
  --jb-tree-focus-ring-offset: var(--jb-gray-2);
  --jb-tree-disabled-text: var(--jb-gray-7);
}

.jb-dynamic-tree {
  background-color: var(--jb-tree-bg);
  color: var(--jb-tree-text);
}

.jb-dynamic-tree .jb-tree-item-button {
  color: var(--jb-tree-text);
}

.jb-dynamic-tree .jb-tree-item-button[data-disabled='true'] {
  color: var(--jb-tree-disabled-text);
}

.jb-dynamic-tree .jb-tree-item-button[data-selected='true'] {
  color: var(--jb-tree-item-selected-text);
}

.jb-dynamic-tree .jb-tree-item-overlay {
  background-color: transparent;
}

.jb-dynamic-tree
  .jb-tree-item-button:hover:not([data-disabled='true']):not(
    [data-selected='true']
  )
  .jb-tree-item-overlay {
  background-color: var(--jb-tree-item-hover-bg);
}

.jb-dynamic-tree
  .jb-tree-item-button:active:not([data-disabled='true']):not(
    [data-selected='true']
  )
  .jb-tree-item-overlay {
  background-color: var(--jb-tree-item-active-bg);
}

.jb-dynamic-tree
  .jb-tree-item-button:focus-visible:not([data-disabled='true'])
  .jb-tree-item-overlay {
  box-shadow:
    0 0 0 1px var(--jb-tree-focus-ring-offset),
    0 0 0 3px var(--jb-tree-focus-ring);
}

.jb-dynamic-tree
  .jb-tree-item-button[data-selected='true']
  .jb-tree-item-overlay {
  background-color: var(--jb-tree-item-selected-bg);
}

.jb-dynamic-tree .jb-tree-item-disclosure {
  color: var(--jb-tree-disclosure);
}

.jb-dynamic-tree
  .jb-tree-item-button:not([data-selected='true']):not([data-disabled='true'])
  .jb-tree-item-disclosure:hover {
  color: var(--jb-tree-disclosure-hover);
}

.jb-dynamic-tree
  .jb-tree-item-button[data-disabled='true']
  .jb-tree-item-disclosure {
  color: var(--jb-tree-disabled-text);
}

.jb-dynamic-tree .jb-tree-item-icon {
  color: var(--jb-tree-icon);
}

.jb-dynamic-tree
  .jb-tree-item-button[data-selected='true']
  .jb-tree-item-disclosure,
.jb-dynamic-tree .jb-tree-item-button[data-selected='true'] .jb-tree-item-icon {
  color: currentColor;
}

.jb-dynamic-tree .jb-tree-item-end {
